from typing import List

class Solution:
    def occurrencesOfElement(self, nums: List[int], queries: List[int], x: int) -> List[int]:
        # Preprocess: collect all indices where x appears in nums
        indices = []
        for i, num in enumerate(nums):
            if num == x:
                indices.append(i)

        # Process queries
        result = []
        for q in queries:
            if q <= len(indices):
                result.append(indices[q - 1])
            else:
                result.append(-1)

        return result
